from flask import Flask, request, jsonify
from prometheus_client import start_http_server, Counter, Histogram

app = Flask(__name__)

# Define Prometheus metrics
request_count = Counter('api_request_total', 'Total number of API requests')
request_latency = Histogram('api_request_latency_seconds', 'Latency of API requests')

@app.route('/metrics', methods=['GET'])
def metrics():
    return start_http_server(8000)

@app.route('/api/data', methods=['POST'])
@request_latency.time()
def api_data():
    request_count.inc()
    user_id = request.headers.get('X-User-ID')
    api_key = request.headers.get('X-API-Key')
    body = request.json

    # Log or process the data as needed
    print(f"User ID: {user_id}, API Key: {api_key}, Body: {body}")

    return jsonify({"message": "Data received"}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)